package pack

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"text/template"

	"gopkg.in/yaml.v3"
)

type PackConfig struct {
	Name     string            `yaml:"name"`
	Version  string            `yaml:"version"`
	Values   map[string]string `yaml:"values"`
	Template string            `yaml:"template"`
}

func LoadPack(path string) (*PackConfig, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read pack file: %w", err)
	}
	var cfg PackConfig
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parse pack file: %w", err)
	}
	return &cfg, nil
}

func Render(cfg *PackConfig, overrides map[string]string) ([]byte, error) {
	// Merge values: overrides take precedence
	merged := make(map[string]string)
	for k, v := range cfg.Values {
		merged[k] = v
	}
	for k, v := range overrides {
		merged[k] = v
	}

	tplData, err := os.ReadFile(cfg.Template)
	if err != nil {
		return nil, fmt.Errorf("read template: %w", err)
	}

	tmpl, err := template.New("stack").Parse(string(tplData))
	if err != nil {
		return nil, fmt.Errorf("parse template: %w", err)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, merged); err != nil {
		return nil, fmt.Errorf("render template: %w", err)
	}
	return buf.Bytes(), nil
}

func Install(name string, rendered []byte) error {
	cmd := exec.Command("docker", "stack", "deploy", "-c", "-", "--with-registry-auth", name)
	cmd.Stdin = bytes.NewReader(rendered)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	return cmd.Run()
}

func Uninstall(name string) error {
	cmd := exec.Command("docker", "stack", "rm", name)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	return cmd.Run()
}
GOEOF

cat > cmd/main.go << 'GOEOF'
package main

import (
	"fmt"
	"os"
	"strings"

	"github.com/ccvass/swarmex/swarmex-pack"
)

func main() {
	if len(os.Args) < 2 {
		usage()
		os.Exit(1)
	}

	packFile := "swarmex-pack.yml"
	overrides := make(map[string]string)

	// Parse --set and --pack-file from args
	args := os.Args[2:]
	var positional []string
	for i := 0; i < len(args); i++ {
		switch {
		case args[i] == "--set" && i+1 < len(args):
			i++
			parts := strings.SplitN(args[i], "=", 2)
			if len(parts) == 2 {
				overrides[parts[0]] = parts[1]
			}
		case args[i] == "--pack-file" && i+1 < len(args):
			i++
			packFile = args[i]
		default:
			positional = append(positional, args[i])
		}
	}

	switch os.Args[1] {
	case "install", "upgrade":
		if len(positional) < 1 {
			fmt.Fprintln(os.Stderr, "usage: swarmex-pack install <name> [--set key=value]")
			os.Exit(1)
		}
		cfg, err := pack.LoadPack(packFile)
		fatal(err)
		rendered, err := pack.Render(cfg, overrides)
		fatal(err)
		fatal(pack.Install(positional[0], rendered))
		fmt.Printf("✓ %s installed\n", positional[0])

	case "uninstall":
		if len(positional) < 1 {
			fmt.Fprintln(os.Stderr, "usage: swarmex-pack uninstall <name>")
			os.Exit(1)
		}
		fatal(pack.Uninstall(positional[0]))
		fmt.Printf("✓ %s removed\n", positional[0])

	case "render":
		cfg, err := pack.LoadPack(packFile)
		fatal(err)
		rendered, err := pack.Render(cfg, overrides)
		fatal(err)
		os.Stdout.Write(rendered)

	default:
		usage()
		os.Exit(1)
	}
}

func usage() {
	fmt.Fprintln(os.Stderr, `swarmex-pack — Helm-like packaging for Docker Swarm

Commands:
  install <name>   Deploy a stack from pack template
  upgrade <name>   Update an existing stack (same as install)
  uninstall <name> Remove a stack
  render           Print rendered YAML to stdout

Flags:
  --set key=value  Override a template value
  --pack-file      Path to pack file (default: swarmex-pack.yml)`)
}

func fatal(err error) {
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}
}
GOEOF

