			svc.Spec.TaskTemplate.Placement = &swarm.Placement{}
		}
		// Merge with existing constraints (don't overwrite user-defined ones)
		existing := svc.Spec.TaskTemplate.Placement.Constraints
		for _, c := range constraints {
			if !containsConstraint(existing, c) {
				existing = append(existing, c)
			}
		}
		svc.Spec.TaskTemplate.Placement.Constraints = existing
	}

	_, err = c.client.ServiceUpdate(ctx, serviceID, svc.Version, svc.Spec, types.ServiceUpdateOptions{})
	if err != nil {
		c.logger.Error("affinity update failed", "service", svc.Spec.Name, "error", err)
	}
}

